package es.ull.project.domain.entity;
// TODO: Change the types of some attributes as needed

import java.util.Objects;
import java.util.Optional;
import java.util.UUID;

public class Container {

    /**
     * Identifier of the container. It is a computed attribute.
     */
    private final UUID containerId;

    /**
     * Physical location of the container.
     */
    private String ubicacion;

    /**
     * Type of waste collected by the container.
     */
    private String tipoResiduo;

    /**
     * Waste demand generated by the container.
     */
    private double demandaResiduos;

    /**
     * Service zone where the container is located (optional).
     */
    private String zonaServicio;

    public Container(String ubicacion, String tipoResiduo,
                     double demandaResiduos, String zonaServicio) {
        this.containerId = UUID.randomUUID();
        this.ubicacion = ubicacion;
        this.tipoResiduo = tipoResiduo;
        this.demandaResiduos = demandaResiduos;
        this.zonaServicio = zonaServicio;
    }

    public UUID getContainerId() {
        return this.containerId;
    }

    public String getUbicacion() {
        return this.ubicacion;
    }

    public void setUbicacion(String ubicacion) {
        this.ubicacion = ubicacion;
    }

    public String getTipoResiduo() {
        return this.tipoResiduo;
    }

    public void setTipoResiduo(String tipoResiduo) {
        this.tipoResiduo = tipoResiduo;
    }

    public double getDemandaResiduos() {
        return this.demandaResiduos;
    }

    public void setDemandaResiduos(double demandaResiduos) {
        this.demandaResiduos = demandaResiduos;
    }

    public Optional<String> getZonaServicio() {
        return Optional.ofNullable(this.zonaServicio);
    }

    public void setZonaServicio(String zonaServicio) {
        this.zonaServicio = zonaServicio;
    }

    @Override
    public boolean equals(Object otherObject) {
        if (this == otherObject) {
            return true;
        }
        if (otherObject == null) {
            return false;
        }
        if (getClass() != otherObject.getClass()) {
            return false;
        }
        final Container otherContainer = (Container) otherObject;
        return Objects.equals(this.containerId, otherContainer.containerId);
    }

    @Override
    public int hashCode() {
        return Objects.hash(this.containerId);
    }

    @Override
    public String toString() {
        return String.format(
            "Container={id=%s, ubicacion=%s, tipoResiduo=%s, demandaResiduos=%s, zonaServicio=%s}",
            this.containerId,
            this.ubicacion,
            this.tipoResiduo,
            this.demandaResiduos,
            this.zonaServicio
        );
    }
}